import scala.collection.mutable.PriorityQueue

def solve(n: Long, edges: Array[Array[Long]]): Long = {
  val adj = Array.fill(n.toInt)(List.empty[(Int, Long, Long)])
  for (edge <- edges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    val s = edge(2)
    val e = edge(3)
    adj(u) = adj(u) :+ (v, s, e)
  }
  val dist = Array.fill(n.toInt)(Long.MaxValue)
  dist(0) = 0L
  val pq = PriorityQueue[(Long, Int)]()
  pq += (0L, 0)
  while (pq.nonEmpty) {
    val (current_time, u) = pq.dequeue()
    if (u == n - 1) return current_time
    if (current_time > dist(u)) {
      continue
    }
    for ((v, s, e) <- adj(u)) {
      val earliest = math.max(current_time, s)
      if (earliest > e) continue
      val arrival = earliest + 1
      if (arrival < dist(v)) {
        dist(v) = arrival
        pq += (arrival, v)
      }
    }
  }
  -1
}
